const checks = [];

function check(name, condition, detail = "") {
  checks.push({ name, ok: Boolean(condition), detail });
}

function hasAll(source, patterns) {
  return patterns.every((pattern) => source.includes(pattern));
}

function hasAllNormalizedNewlines(source, patterns) {
  const normalizedSource = String(source).replace(/\r\n?/g, "\n");
  return patterns.every((pattern) => normalizedSource.includes(String(pattern).replace(/\r\n?/g, "\n")));
}

function sourceBetween(source, start, end) {
  const startIndex = source.indexOf(start);
  if (startIndex < 0) return "";
  const endIndex = source.indexOf(end, startIndex + start.length);
  return endIndex < 0 ? source.slice(startIndex) : source.slice(startIndex, endIndex);
}

function hasTeacherLessonHubAttendanceSettings(source) {
  return /<TeacherLessonHubV2[\s\S]*?allRecords=\{records\}[\s\S]*?attendanceSettings=\{attendanceSettings\}/.test(source)
    && /function TeacherLessonHubV2\(\{[\s\S]*?allRecords = \[\],[\s\S]*?attendanceSettings = defaultAttendanceSettings/.test(source)
    && /<LessonJournalDetail[\s\S]*?allRecords=\{allRecords\}[\s\S]*?attendanceSettings=\{attendanceSettings\}/.test(source);
}

function hasTeacherReminderAboveCalendarControls(source) {
  const hubIndex = source.indexOf("function TeacherLessonHubV2");
  const reminderIndex = source.indexOf("<AcademyReminderPanel", hubIndex);
  const topIndex = source.indexOf("<header className=\"pageTop teacherCalendarTop\">", hubIndex);
  const calendarIndex = source.indexOf("<section className=\"calendarShell teacherCalendarShell\">", hubIndex);
  return hubIndex >= 0 && reminderIndex > hubIndex && reminderIndex < topIndex && topIndex < calendarIndex;
}

